import{_ as a,o as n,c as t,O as s}from"./chunks/framework.92cbe775.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"ExecGov","text":"Governed AI Execution","tagline":"Start with Python scripts as the first mature execution asset. The web console already supports Python and Shell script onboarding so scattered and risky automation can move into one governed entry with traceable execution records.","actions":[{"theme":"brand","text":"Try for Free","link":"/en/guide/getting-started"},{"theme":"alt","text":"Apply as Design Partner","link":"/en/contact#lead-form"},{"theme":"alt","text":"Why ExecGov","link":"/en/materials/why-execgov"}]},"features":[{"title":"Bring scripts under control","details":"Turn loose scripts, scheduled jobs, and manual commands into one formal entry instead of relying on memory and tribal knowledge."},{"title":"Keep records reviewable","details":"You can trace who executed what, when it happened, and what the result was."},{"title":"Make risk boundaries explicit","details":"High-risk actions require confirmation, and tenant and role boundaries stay isolated."},{"title":"Connect local capability","details":"Local scripts, intranet APIs, and private resources can join the cloud control plane without being fully exposed."}]},"headers":[],"relativePath":"en/index.md","filePath":"en/index.md","lastUpdated":1776068451000}'),i={name:"en/index.md"};function r(l,e,o,d,c,p){return n(),t("div",null,e[0]||(e[0]=[s('<div class="landing-shell"><section class="landing-band landing-band--partner"><div class="partner-banner"><div class="partner-banner__copy"><p class="landing-kicker">Design Partners</p><h2>Looking for 1-3 design partners</h2><p class="landing-lead"> If your team is already struggling with a large script estate and a growing pile of automation tasks, the current limited deep-collaboration plan is meant for you. The goal is not to sell a large platform first. The goal is to take one real workflow and turn it into <strong>a repeatable sample that can be requested, confirmed, executed, and reviewed later</strong>. </p><div class="partner-banner__chips"><span>1-3 real paid slots</span><span>Best for teams with many scripts already</span><span>Time-limited deep collaboration</span></div></div><div class="partner-banner__actions"><a class="cta-button cta-button--brand" href="./contact.html#lead-form">Apply as a design partner</a><a class="cta-button" href="mailto:zmx2321@163.com?subject=ExecGov%20Design%20Partner">Email directly</a></div></div></section><section class="landing-band landing-band--brand landing-band--brand-story"><div class="landing-brand"><div class="landing-brand__copy"><p class="landing-kicker">Brand Signal</p><h2>Bring scattered and risky team scripts under explicit control</h2><p class="landing-lead"><strong>Bring scattered and risky team scripts under explicit control. Who ran what, when it happened, and what the result was all stay on record, and when something breaks there is a traceable path back.</strong></p><p class="landing-lead"><strong>ExecGov is a multi-tenant capability-governance and execution platform that treats Python scripts as its first mature execution asset.</strong></p><p class="landing-lead"><strong>Exec</strong> comes from <strong>Execution</strong> and <strong>Gov</strong> comes from <strong>Governance</strong>. This is not a government-project label. It means <strong>AI, scripts, local resources, and online capabilities should all execute inside governance boundaries</strong>. If a capability cannot actually land inside rules, it is outside the scope of what ExecGov is trying to solve. </p><p class="landing-lead"> Many teams do not lack scripts. They lack a <strong>unified entry point, permission boundaries, confirmation before risky actions, and result traceability</strong>. Scripts end up scattered across personal laptops, shared drives, servers, and chat history, and nobody can clearly answer who is allowed to run what, when it should run, or where the result goes. </p><p class="landing-lead"> ExecGov currently stabilizes the most common and most reusable capability shape first: Python scripts. You can already walk through a simplified public experience flow before deciding whether to connect a real scenario. </p><p class="landing-lead"> The current web upload entry already accepts <strong>Python and Shell</strong> text scripts in one place. The public experience page deliberately shows <strong>Python <code>task_brief_demo.py</code> on the left and Shell <code>clean_log_demo.sh</code> on the right</strong>. The real experience scripts come from <code>exec-gov-ai-skill-platform-script/tenant_1000/experience/</code> and are hot-swapped through the manifest mapping. </p><p class="landing-lead"> The platform has already completed its first compatibility upgrade: a general resource layer and an executor registry layer are in place, and the first non-script sample, <strong>HTTP capability access</strong>, has already landed in the <strong>public</strong> super-admin domain to verify the new path of <strong>resource model + executor + audit chain</strong>. The tenant side currently exposes only a <strong>read-only ledger</strong> so users can see summaries of HTTP resources, authentication style, and write boundaries that have already been granted to them. That does not mean tenants can already self-serve generic API onboarding. For now, configuration, credential governance, and dry-run verification still stay inside the <strong>public</strong> governance domain. The more urgent commercial priority remains stabilizing the <strong>1.1</strong> low-support loop for registration, payment, renewal, and expiry recovery. </p><p class="landing-lead"> That <strong>1.1</strong> line has already landed first on the <strong>public</strong> side: order creation, payment confirmation, activation and renewal, renewal-reminder scans, and expiry shutdown scans all feed customer and tenant status updates back into the system. That still does not mean end users already have a complete self-service payment experience. Real third-party payment gateways, a user-facing billing center, and outbound reminder channels are still being added. </p><p class="landing-lead"> At the same time, the standard shared-SaaS tenant frontend has already been established. From <strong>tenant_1003+</strong> onward, standard SaaS customers no longer default to cloning a dedicated frontend project per customer. They first enter the shared tenant frontend instead. It can already carry formal tenant entry, while branding, initialization, and finer menu boundaries are still being tightened. </p><div class="landing-brand__chips"><span>Script governance</span><span>Execution traceability</span><span>Audit trail</span><span>Local bridge</span><span>Security boundary</span><span>Shared SaaS</span></div><div class="landing-brand__quick-grid"><article class="landing-brand__quick-card"><span>First mature execution asset</span><strong>Python scripts</strong></article><article class="landing-brand__quick-card"><span>First problem to solve well</span><strong>Unifying scattered scripts and governing execution risk</strong></article></div><p class="landing-lead"> Whether you are an individual developer, a team lead, or an enterprise IT manager, the first goal here is to tell you <strong>which problems ExecGov can solve for you now</strong>, <strong>which entry path fits you first</strong>, and <strong>what the lowest-friction next step is</strong>. </p></div><div class="landing-brand__panel"><article class="landing-brand__signal-card"><div class="landing-brand__signal-head"><span>ENTRY SYSTEM</span><span>SYNC 01</span></div><p class="landing-brand__signal-summary">From the no-login experience path to design partners and then real onboarding, every entry is designed to help you confirm first whether scripts can be controlled, run safely, and stay reviewable before deciding how to land them.</p><div class="landing-brand__signal-list"><div class="landing-brand__signal-item"><strong>Entry</strong><span>Free path, local expansion, team edition, enterprise delivery</span></div><div class="landing-brand__signal-item"><strong>Capability</strong><span>Governed execution, audit trail, local bridge</span></div></div><div class="landing-brand__signal-tags"><span>Unified Entry</span><span>Policy Inside</span></div></article><div class="landing-brand__meta-grid"><article class="landing-brand__meta"><span class="link-panel-label">Mature Asset</span><strong>Python scripts are the first mature execution asset</strong><p>Stabilize onboarding, execution, result return, and traceability for the script shape first, then expand to more capability types.</p></article><article class="landing-brand__meta"><span class="link-panel-label">Next Step</span><strong>Start by turning scattered scripts into one formal entry</strong><p>Clarify directories, boundaries, risky actions, and result return first, then decide how the real team environment should connect.</p></article><article class="landing-brand__meta landing-brand__meta--wide"><span class="link-panel-label">Design Partner</span><strong>1-3 design-partner slots are open now</strong><p>This is a better fit for teams that already have many scripts, automation jobs, and boundary problems and want to build one delivery-grade governance sample first.</p></article><article class="landing-brand__meta landing-brand__meta--wide landing-brand__meta--trail"><span class="link-panel-label">Audit Trail</span><strong>Who ran what, when it happened, and what the result was should all stay reviewable</strong><p>The point is not to move scripts somewhere else. The point is to connect the entry point, permission boundaries, execution process, result return, and later accountability into one traceable chain.</p><div class="landing-brand__record-grid"><div class="landing-brand__record-item"><span>Origin</span><strong>Entry path, tenant, and operator all stay attributable</strong></div><div class="landing-brand__record-item"><span>Boundary</span><strong>Scripts, parameters, permissions, and risky actions remain checkable</strong></div><div class="landing-brand__record-item"><span>Result</span><strong>Logs, artifacts, status, and failure reasons remain reviewable</strong></div><div class="landing-brand__record-item"><span>Accountability</span><strong>After an incident, you know who to find and what to fix</strong></div></div></article></div></div></div></section><section class="landing-band landing-band--overview landing-band--overview-center"><div class="landing-section-head"><p class="landing-kicker">Platform Thesis</p><h2>Move from &quot;AI can chat&quot; to &quot;AI can execute inside rules&quot;</h2><p class="landing-lead"> At the project layer, <strong>ExecGov</strong> is positioned as <strong>An Open &amp; Secure AI Agent Execution Layer</strong>. At the product layer, it is presented externally as <strong>ExecGov</strong>. The real problem it wants to solve is not the chat experience itself. It is <strong>how real tasks can be executed reliably inside rules</strong>. </p><p class="landing-lead"> For the current public site, the most stable way to explain it is in three layers: the <strong>foundation layer</strong> handles multi-tenancy, security, permissions, and audit; the <strong>abstraction layer</strong> expresses capability units as Skills; and the <strong>implementation layer</strong> is currently led by Python scripts while HTTP resources are already validating the second capability shape. </p><p class="landing-lead"> This round also tightened the permission boundary: the <strong>whitelisted tenant admin</strong> now keeps only the minimal cross-tenant console entry, and no longer sees platform-governance pages such as <strong>HTTP capability access</strong>. Runtime and menu logic also no longer rely on unsafe shortcuts such as <code>user_id == 1</code> to infer administrator status. </p><p class="landing-lead"> From the commercial point of view, the practical progress right now is not &quot;the platform already has a complete SaaS billing desk.&quot; It is that the operator-side billing and lifecycle skeleton is already running. The end-user self-service path is still being completed. </p><p class="landing-lead"> Formal customers also no longer have only one option. Standard SaaS customers can start on the shared tenant frontend first. When stronger isolation, exclusive pages, exclusive branding, or deeper deployment control is needed, the path can continue into single-tenant delivery or private deployment. </p></div><div class="landing-metrics"><article class="metric-card"><span class="metric-value">Controlled</span><span class="metric-label">execution</span><p>Critical actions require confirmation before they run, which prevents AI from directly overreaching into real operations.</p></article><article class="metric-card"><span class="metric-value">Auditable</span><span class="metric-label">process trace</span><p>From request input to final result, the chain can stay on record for governance, review, and compliance needs.</p></article><article class="metric-card"><span class="metric-value">Bridgeable</span><span class="metric-label">local capability</span><p>Scripts, intranet APIs, and private resources can be pulled gradually into one governed entry.</p></article><article class="metric-card"><span class="metric-value">Evolvable</span><span class="metric-label">growth path</span><p>The path is clear from the free path to local script slots, the team edition, and enterprise delivery without rewriting from scratch.</p></article></div></section><section class="landing-band landing-band--commercial"><div class="landing-section-head"><p class="landing-kicker">Commercial Route</p><h2>Start from the entry path that matches the problem you actually have</h2><p class="landing-lead"> The more stable explanation today is not &quot;try it first and decide later&quot; in the abstract. It is to judge first whether you belong to the <strong>free path</strong>, <strong>local script-slot expansion</strong>, <strong>standard team edition</strong>, or <strong>enterprise delivery</strong>. </p></div><div class="landing-grid landing-grid--three"><article class="mode-card"><span class="link-panel-label">Free</span><h3>Individual developers and technical early adopters</h3><p>You do not need to understand the full architecture first. Start by trying one governed script-dispatch flow, then decide whether that model deserves formal adoption.</p></article><article class="mode-card"><span class="link-panel-label">Team</span><h3>Team managers and technical leads</h3><p>Judge first whether you only need personal-space expansion or whether you have already entered formal team collaboration. For multi-user collaboration, start from the shared-SaaS tenant path.</p></article><article class="mode-card"><span class="link-panel-label">Enterprise</span><h3>Enterprise decision makers and IT managers</h3><p>Judge private deployment, intranet access, data security, and compliance fit first, then decide whether to move into formal deployment and delivery.</p></article></div><div class="landing-inline-links"><a href="./guide/getting-started.html">Try for free</a><a href="./contact.html#lead-form">Apply as a design partner</a><a href="./materials/why-execgov.html">Why I Am Building ExecGov</a><a href="./product/editions.html">See the current stage</a></div></section><section class="landing-band landing-band--overview"><div class="landing-section-head"><p class="landing-kicker">Showroom</p><h2>Not a hello demo, but three sample cases you can use in project conversations</h2><p class="landing-lead"> These cases are not here to prove that a button can be clicked through. They are here to show how ExecGov can turn complex, risky, failure-prone script flows into <strong>a service that can be requested, confirmed, executed, and reviewed later</strong>. </p></div><div class="landing-grid landing-grid--three"><a class="link-panel" href="./materials/case-studies.html#k8s-security-report"><span class="link-panel-label">Case 01</span><strong>Automatically inspect a K8s cluster and generate a security report</strong><p>From the inspection request to node-level checks, risk confirmation, and final report generation, the entire chain stays traceable and auditable.</p></a><a class="link-panel" href="./materials/case-studies.html#multi-cloud-cost-analysis"><span class="link-panel-label">Case 02</span><strong>Cross-cloud cost analysis and optimization recommendations</strong><p>Turn cloud-bill pull, cleaning, aggregation, anomaly detection, and optimization advice into one governed execution service.</p></a><a class="link-panel" href="./materials/case-studies.html#ops-data-automation"><span class="link-panel-label">Case 03</span><strong>Operations data automation and anomaly tracking</strong><p>Bring recurring reporting, file handling, import/export, and anomaly-tracking flows into one entry point and cut manual rework.</p></a></div><div class="landing-inline-links"><a href="./materials/case-studies.html">View the full case studies</a><a href="./contact.html#lead-form">Bring a real scenario</a></div></section><section class="landing-band landing-band--overview"><div class="landing-section-head"><p class="landing-kicker">Best Fit</p><h2>The current priority is serving these three customer types well</h2><p class="landing-lead"> This is not the moment to spread the line too wide. For a platform still being pushed forward continuously by one founder, it matters more to go deep on the three customer types that are easiest to close, easiest to reuse, and closest to the current code capability. </p></div><div class="landing-grid landing-grid--three"><article class="mode-card"><span class="link-panel-label">01</span><h3>E-commerce, content, and operations data automation</h3><p>Best for teams that already have many spreadsheet, reporting, scraping, cleaning, import, and export scripts but suffer from fragmented entry points, unstable execution, and poor traceability.</p></article><article class="mode-card"><span class="link-panel-label">02</span><h3>Technical-team script governance and automation operations</h3><p>Best for teams doing log cleanup, inspections, batch jobs, scheduled reports, script governance, and execution traceability.</p></article><article class="mode-card"><span class="link-panel-label">03</span><h3>Smaller formal customers who need intranet or private deployment</h3><p>Best for customers who care about tenant isolation, permission boundaries, intranet constraints, and private deployment but do not want to buy a heavy system on day one.</p></article></div></section><section class="landing-band"><div class="landing-section-head"><p class="landing-kicker">Brand Position</p><h2>Brand positioning</h2><p class="landing-lead"> Externally, use <strong>ExecGov</strong> as one unified brand instead of splitting it into separate project-name and product-name narratives. The repository slug and existing technical identifiers can keep their historical naming for now. </p></div><div class="landing-grid landing-grid--two"><article class="mode-card"><span class="link-panel-label">Brand</span><h3>ExecGov</h3><p><strong>Position:</strong> an enterprise AI execution and governance platform</p><p><strong>Slogan:</strong> make every automation reliable and governed.</p><p>Use this framing across the website, materials, proposals, contracts, and formal delivery conversations.</p></article><article class="mode-card"><span class="link-panel-label">Method</span><h3>Govern first, execute for real</h3><p><strong>Current strategy:</strong> stabilize script-shaped capability first, then expand toward APIs, templates, connectors, and approval flows.</p><p><strong>Naming note:</strong> <code>ExecGov = Execution + Governance</code>, and <code>Gov</code> means governance, not a government project.</p><p><strong>Current state:</strong> the main repository slug <code>exec-gov-ai-skill-platform</code> has already been unified, while the directory path <code>execgov-cli/</code> keeps historical naming and the external CLI command is already unified as <code>execgov-cli</code>.</p></article></div></section><section id="founder-note" class="landing-band landing-band--overview landing-band--founder"><div class="landing-section-head"><p class="landing-kicker">Founder Note</p><h2>Who is building ExecGov, and why the platform is worth understanding further</h2><p class="landing-lead"> I am currently based in Hangzhou and continuing this as a bootstrapped micro-business. My long-term mainline is <strong>8 years of frontend delivery</strong>, with the last <strong>2 years</strong> focused on strengthening Python automation and small full-stack execution loops. The core goal is not to tell a giant platform story. It is to turn the delivery problems I kept running into <strong>script onboarding</strong>, <strong>permission boundaries</strong>, <strong>execution traceability</strong>, and <strong>local bridging</strong> into a product that actually saves people time and reduces rework. </p><p class="landing-lead"> If this has to collapse into one sentence, it is this: <strong>turn the platform into a small business that keeps solving real problems and can sustain itself through stable operation.</strong></p><div class="landing-inline-links"><a href="./contact.html#lead-form">Continue the scenario discussion</a><a href="./materials/founder-profile.html">View the full delivery background</a><a href="https://zmx2321.github.io/vite-blog" target="_blank" rel="noreferrer">View the public blog</a></div></div><div class="landing-metrics"><article class="metric-card"><span class="metric-value">Hangzhou</span><span class="metric-label">bootstrapped build</span><p>This is not a funding-driven large project. The goal is to keep solving real problems and make the platform capable of supporting itself as a business.</p></article><article class="metric-card"><span class="metric-value">8 + 2</span><span class="metric-label">years frontend / years reinforcement</span><p>The long-term line is frontend, GIS visualization, and enterprise admin work, with the last two years focused on Python automation and small full-stack loops.</p></article><article class="metric-card"><span class="metric-value">Web + CLI + Local</span><span class="metric-label">practical bridge first</span><p>The current focus is getting the web entry and local bridge truly usable before talking too much about farther capabilities.</p></article><article class="metric-card"><span class="metric-value">Four paths</span><span class="metric-label">clear way in</span><p>Start from the free path, then move through local script slots, the standard team edition, and enterprise delivery instead of forcing everyone into the same route.</p></article></div></section><section class="landing-band landing-band--flow"><div class="landing-section-head"><p class="landing-kicker">Execution Flow</p><h2>How the platform turns a request into deliverable execution</h2></div><div class="landing-flow"><article class="flow-card"><span class="flow-index">01</span><h3>Intent understanding and plan generation</h3><p>Understand the task first and produce an execution plan instead of directly calling low-level capability with unchecked privilege.</p></article><article class="flow-card"><span class="flow-index">02</span><h3>Capability matching and security decision</h3><p>Organize scripts, Skills, templates, and later capability packs into a formal catalog controlled by permissions and rules.</p></article><article class="flow-card"><span class="flow-index">03</span><h3>Human confirmation and real execution</h3><p>Critical actions need confirmation first, and the current focus is making the cloud and local execution positions explicit.</p></article><article class="flow-card"><span class="flow-index">04</span><h3>Result return and audit trail</h3><p>From output artifacts to logs and audit, the platform is built around traceability instead of a one-off run that disappears.</p></article></div></section><section class="landing-band"><div class="landing-section-head"><p class="landing-kicker">Delivery Toolkit</p><h2 class="landing-heading--nowrap-desktop">Three pages formal projects often read first</h2><p class="landing-lead"> This group is meant for visitors who are already preparing to move into a real project. It explains the <strong>file chain, deliverables, and onboarding preparation</strong> in one pass. </p></div><div class="landing-grid landing-grid--three"><a class="link-panel" href="./product/file-results.html"><span class="link-panel-label">Files</span><strong>File upload / result download</strong><p>Best for reporting, Excel, batch processing, and workflows that return result files. Explain the input-file and output-artifact chain clearly first.</p></a><a class="link-panel" href="./product/deliverables.html"><span class="link-panel-label">Deliverables</span><strong>Deliverables / document entry</strong><p>Best for formal delivery conversations so customers know exactly which URLs, accounts, instructions, and result entries they will receive.</p></a><a class="link-panel" href="./product/onboarding-checklist.html"><span class="link-panel-label">Checklist</span><strong>Customer onboarding checklist</strong><p>Best for aligning script directories, README files, sample files, dependencies, and risky boundaries together with presales, implementation, and the customer.</p></a></div><div class="landing-inline-links"><a href="./product/customer-flow.html">Customer flow / delivery</a><a href="./product/file-results.html">File upload / result download</a><a href="./product/onboarding-checklist.html">Customer onboarding checklist</a></div></section><section class="landing-band landing-band--audience"><div class="landing-section-head"><p class="landing-kicker">Who It Fits</p><h2>It is a stronger fit for these roles</h2></div><div class="landing-grid landing-grid--three"><article class="landing-card"><h3>Enterprise delivery teams</h3><p>They need one tenant per customer, one delivery entry, and a sustainable way to expand to multiple customers without mixing them into one backend.</p></article><article class="landing-card"><h3>Platform operators</h3><p>They need to manage templates, announcements, audit, customer ledgers, and release rollback centrally while keeping tenant boundaries explicit.</p></article><article class="landing-card"><h3>Developers and small teams</h3><p>They need to turn existing scripts into callable, describable, maintainable capability units and choose between the free path, shared SaaS, or local execution as the starting point.</p></article></div></section><section class="landing-band landing-band--modes"><div class="landing-section-head"><p class="landing-kicker">Deployment Modes</p><h2>One governance logic across different deployment shapes</h2></div><div class="landing-grid landing-grid--two"><article class="mode-card"><h3>Single-tenant delivery</h3><p>For enterprise customers who need stronger isolation, dedicated pages, dedicated branding, or deeper deployment control: one customer, one tenant, one entry, and one maintainable capability boundary.</p></article><article class="mode-card"><h3>Standard shared-SaaS tenant</h3><p>From <code>tenant_1003+</code> onward, standard SaaS customers enter the shared tenant frontend first. What is shared is the release cadence, not tenant data, permissions, or results.</p></article><article class="mode-card"><h3>Platform-level governance</h3><p>Manage tenants, templates, announcements, and logs centrally while keeping the isolation line between customers explicit.</p></article><article class="mode-card"><h3>Free experience entry</h3><p>Provide a low-friction first experience and upgrade entry for individual users and smaller teams.</p></article><article class="mode-card"><h3>Local and edge execution</h3><p>The current focus is local environments and the CLI bridge, which is a better fit for scenarios that must connect local scripts and intranet resources.</p></article></div><div class="landing-inline-links"><a href="./product/deployment.html">View deployment modes</a><a href="./product/scenarios.html">View scenarios</a><a href="./product/cli.html">View the CLI guide</a></div></section><section class="landing-band landing-band--roadmap landing-band--roadmap-home"><div class="landing-section-head"><p class="landing-kicker">Roadmap</p><h2>Why now, and what gets built next first</h2><p class="landing-lead"> The current route has two steps: stabilize delivery, experience, and onboarding first, then keep expanding collaboration, capability types, and product support. </p></div><div class="roadmap-grid"><article class="roadmap-card"><span class="roadmap-stage">1.0</span><h3>Stabilize the current delivery version first</h3><p>Make customer delivery, the public experience path, the personal entry, and the minimal CLI chain truly usable before widening scope.</p></article><article class="roadmap-card"><span class="roadmap-stage">Next</span><h3>Then decide what deserves productization</h3><p>Small-team collaboration, quota packages, and more general capability onboarding will keep improving in the next stage.</p></article></div><div class="landing-inline-links"><a href="./product/editions.html">See the current-stage note</a></div></section><section class="landing-band landing-band--links"><div class="landing-grid landing-grid--three"><a class="link-panel" href="./guide/"><span class="link-panel-label">Guide</span><strong>Start here</strong><p>Align the entry paths, roles, and reading order first so you do not keep bouncing between pages without a frame.</p></a><a class="link-panel" href="./guide/getting-started.html"><span class="link-panel-label">Quick Start</span><strong>Getting Started</strong><p>Understand as quickly as possible how to begin from the free path, how script onboarding works, and when the team or enterprise path is the better fit.</p></a><a class="link-panel" href="./guide/faq.html"><span class="link-panel-label">FAQ</span><strong>Frequently Asked Questions</strong><p>Clarify positioning, security boundaries, local onboarding, and who the platform currently fits in one pass.</p></a><a class="link-panel" href="./product/"><span class="link-panel-label">Product</span><strong>Product Overview</strong><p>Understand what the platform is doing, what it is not doing, and what the most accurate external definition is today.</p></a><a class="link-panel" href="./product/capabilities.html"><span class="link-panel-label">Capabilities</span><strong>Core capabilities</strong><p>See multi-tenancy, trusted execution, template distribution, announcement governance, and the CLI bridge on one page.</p></a><a class="link-panel" href="./product/cli.html"><span class="link-panel-label">CLI</span><strong>CLI guide</strong><p>See exactly where local login, capability onboarding, Skill execution, and the Agent skeleton stand right now.</p></a><a class="link-panel" href="./product/customer-flow.html"><span class="link-panel-label">Delivery</span><strong>Customer flow / delivery</strong><p>Understand how customers use the platform, how delivery works, and how hot update forms a formal closed loop.</p></a><a class="link-panel" href="./product/personal-billing-membership.html"><span class="link-panel-label">Billing</span><strong>Billing and membership</strong><p>See how the personal free path pays, how the formal team monthly or annual registration path works, and how far the payment line has already landed.</p></a><a class="link-panel" href="./product/file-results.html"><span class="link-panel-label">Files</span><strong>File upload / result download</strong><p>Best for file-based tasks, reporting outputs, and projects that need downloadable artifacts instead of assuming every result is just text.</p></a><a class="link-panel" href="./product/deliverables.html"><span class="link-panel-label">Deliverables</span><strong>Deliverables / document entry</strong><p>Spell out the final entry points, instructions, and result artifacts customers receive so delivery and later use stay clear.</p></a><a class="link-panel" href="./product/onboarding-checklist.html"><span class="link-panel-label">Checklist</span><strong>Customer onboarding checklist</strong><p>Best for people preparing real script-shaped capabilities and real scenarios: complete the onboarding materials first, then continue into the team or enterprise path.</p></a><a class="link-panel" href="./materials/"><span class="link-panel-label">Materials</span><strong>External materials</strong><p>Separate the platform introduction, value framing, and pitch materials for reading, review, and solution discussion.</p></a></div></section><section class="landing-band landing-band--cta"><div class="cta-card"><div><p class="landing-kicker">Contact</p><h2>The free path, team-edition judgment, and formal delivery consultation are open now.</h2><p class="landing-lead"> If you already have scripts, local environments, permission boundaries, or delivery problems that need a cleaner path, this is the most direct public entry right now. It is designed to receive free-path judgment, local script-slot expansion judgment, team-edition evaluation, and delivery consultation. </p></div><div class="cta-actions"><a class="cta-button cta-button--brand" href="./guide/getting-started.html">Try for free now</a><a class="cta-button" href="./contact.html#lead-form">Discuss a specific scenario</a><a class="cta-button" href="./contact.html#lead-form">Ask about delivery</a></div></div></section></div> --- ',2)]))}const u=a(i,[["render",r]]);export{g as __pageData,u as default};
